INSERT INTO    gather.tb_syslog_rule_mst
(
        syslog_rule_id,
        syslog_rule_nm,
        node_type,
        priority_order,
        alarm_severity,
        occur_str1,
        occur_str2,
        occur_str3,
        occur_except_str1,
        occur_except_str2,
        occur_except_str3,
        use_yn
)
VALUES
(
        NEXTVAL('gather.seq_syslog_rule')
        ,#{syslog_rule_nm}
        ,'*'
        ,1
        ,7
        ,#{occur_str1}

        ,#{occur_str2}


        ,#{occur_str3}


        ,#{occur_except_str1}


        ,#{occur_except_str2}


        ,#{occur_except_str3}


        ,#{use_yn}

)

