mapper.select:
SELECT src_ip, src_nren_id, src_nren_name, src_country_code, dst_ip, dst_nren_id, dst_nren_name, dst_country_code, packet_bytes, row_num FROM ( SELECT src_ip, src_nren_id, src_nren_name, src_country_code, dst_ip, dst_nren_id, dst_nren_name, dst_country_code, SUM(packet_bytes) AS packet_bytes, row_number() OVER ( ORDER BY CASE WHEN src_nren_id IS NULL AND dst_nren_id IS NULL THEN 0 ELSE 2 END DESC, SUM(packet_bytes) DESC ) AS row_num FROM gather.tb_mdb_sflow_traffic_day dt WHERE 1=1 AND dt.collect_timestamp <= CURRENT_DATE AND dt.collect_timestamp >= CURRENT_DATE - INTERVAL '5 days'
AND src_nren_id = #{src_nren_name}
AND src_ip LIKE '%' || #{src_ip} || '%'
AND dst_nren_id = #{dst_nren_name}
AND dst_ip LIKE '%' || #{dst_ip} || '%'
GROUP BY src_ip, src_nren_id, src_nren_name, src_country_code, dst_ip, dst_nren_id, dst_nren_name, dst_country_code ) AS subquery WHERE 1=1
AND row_num <= #{top_n}
AND row_num < 101

SELECT src_protocol, src_port, dst_protocol, dst_port, packet_bytes, rank_order FROM ( SELECT src_protocol, src_port, dst_protocol, dst_port, SUM(packet_bytes) packet_bytes , row_number() over (ORDER BY CASE WHEN src_protocol IS NULL AND dst_protocol IS NULL THEN 0 ELSE 2 END DESC, SUM(packet_bytes) DESC) rank_order FROM gather.tb_mdb_sflow_traffic_day dt WHERE 1=1 AND dt.collect_timestamp <= CURRENT_DATE AND dt.collect_timestamp >= CURRENT_DATE - interval '5 days'
AND src_port = #{src_protocol}
AND src_port like '%' || #{src_port} || '%'
AND dst_port = #{dst_protocol}
AND dst_port like '%' || #{dst_port} || '%'
GROUP BY src_protocol, src_port, dst_protocol, dst_port ) dt WHERE 1=1
AND rank_order <= #{top_n}
AND rank_order < 101

WITH TRAFFIC_DATA AS ( SELECT NM.NODE_NUM, NM.NODE_NM, N.ID AS SDN_NODE_ID, PM.IF_NUM, I.ID AS SDN_IF_ID, I.IF_NAME, LT.TX_BIT_RATE, LT.RX_BIT_RATE, LT.TX_PKT_RATE, LT.RX_PKT_RATE, LT.MEASURED_DATETIME FROM IP_SDN.TB_LINK_TRAFFIC LT INNER JOIN IP_SDN.TB_INTERFACE I ON LT.IF_ID = I.ID INNER JOIN RESOURCE.TB_PORT_MST PM ON PM.IF_ID = LOWER(I.IF_NAME) INNER JOIN IP_SDN.TB_NODE N ON I.NODE_ID = N.ID INNER JOIN RESOURCE.TB_NODE_MST NM ON N.ID = NM.IP_SDN_ID::INT WHERE PM.NODE_NUM = NM.NODE_NUM
AND LT.MEASURED_DATETIME BETWEEN NOW()::timestamp - interval '10 min' AND NOW()::timestamp
AND LT.MEASURED_DATETIME > #{start_date}::timestamp
AND LT.MEASURED_DATETIME <= #{end_date}::timestamp
AND nm.NODE_NM = #{node_name}
AND I.IF_NAME = #{if_name}
) SELECT T.NODE_NUM, T.NODE_NM AS NODE_NAME, T.SDN_NODE_ID, T.IF_NUM, T.SDN_IF_ID, T.IF_NAME, T.DIRECTION, T.RX_BIT_RATE, T.RX_PKT_RATE, T.TX_BIT_RATE, T.TX_PKT_RATE, TO_CHAR(T.MEASURED_DATETIME, 'YYYY-MM-DD HH24:MI:SS') AS MEASURED_DATETIME, CASE WHEN (SELECT 1 FROM RCA.TB_ANOMALOUS_1MI_TRAFFIC WHERE STRRESID = T.NODE_NUM AND STRIFID = T.IF_NUM AND MEASURED_DATETIME = T.MEASURED_DATETIME
AND MEASURED_DATETIME BETWEEN NOW()::timestamp - interval '10 min' AND NOW()::timestamp
AND MEASURED_DATETIME > #{start_date}::timestamp
AND MEASURED_DATETIME <= #{end_date}::timestamp
) =1 THEN TRUE ELSE FALSE END AI_RESULT FROM ( SELECT NODE_NUM, NODE_NM, SDN_NODE_ID, IF_NUM, SDN_IF_ID, IF_NAME, 'IN' AS DIRECTION, RX_BIT_RATE, RX_PKT_RATE, 0 AS TX_BIT_RATE, 0 AS TX_PKT_RATE, MEASURED_DATETIME FROM TRAFFIC_DATA UNION ALL SELECT NODE_NUM, NODE_NM, SDN_NODE_ID, IF_NUM, SDN_IF_ID, IF_NAME, 'OUT' AS DIRECTION, 0 AS RX_BIT_RATE, 0 AS RX_PKT_RATE, TX_BIT_RATE, TX_PKT_RATE, MEASURED_DATETIME FROM TRAFFIC_DATA ) T ORDER BY MEASURED_DATETIME DESC

